package com.taxin60sec.backend.payment;
import org.springframework.stereotype.Service;
import java.util.*;
@Service public class PaymentServiceImpl implements PaymentService {private final Map<String,PaymentProvider> providers;public PaymentServiceImpl(List<PaymentProvider> providers){this.providers=providers.stream().collect(java.util.stream.Collectors.toMap(p->p.name().toLowerCase(),p->p));}private PaymentProvider provider(String name){PaymentProvider p=providers.get((name==null?"razorpay":name).toLowerCase());if(p==null)throw new PaymentException("Unsupported payment provider");return p;}public PaymentOrder createOrder(PaymentOrderRequest request){return provider(request.metadata()==null?null:request.metadata().get("provider")).createOrder(request);}public PaymentEvent verifyWebhook(PaymentWebhook webhook){return provider(webhook.provider()).verifyWebhook(webhook);}public Refund refund(RefundRequest request){return provider("razorpay").refund(request);}public Invoice invoice(String paymentId){return provider("razorpay").invoice(paymentId);}}
